#!/usr/bin/env bash
# webgl-webgpu-tsl.sh — WebGL → WebGPU / TSL 迁移 SOP walkthrough for Web 线上展览开发 (虚拟展厅).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="Web 线上展览开发 (虚拟展厅)"
WORKFLOW="WebGL → WebGPU / TSL 迁移"

usage() {
  cat <<EOF
webgl-webgpu-tsl.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./webgl-webgpu-tsl.sh             # interactive
  ./webgl-webgpu-tsl.sh --dry-run
  ./webgl-webgpu-tsl.sh --json
  ./webgl-webgpu-tsl.sh --explain
  ./webgl-webgpu-tsl.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "WebGL → WebGPU / TSL 迁移" 工作流。

一句话: 从「WebGL 撞性能墙 / 想用 compute」到「WebGPU 渲染 + 自动 WebGL2 fallback」——2025–2026 全行业渲染后端代际迁移。

入门 SOP 共 6 步, 失败模式自检 4 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**Audit 现状**：确认 Three.js ≥ r171；清点自定义 GLSL shader 与后期依赖（这些是迁移成本所在）(evidence: [T03-S002])"
  "**升级 + 换 import/renderer**：\`npm i three@latest\`；\`import * as THREE from 'three/webgpu'\` + \`new THREE.WebGPURenderer()\`（该入口含 renderer/材质/灯光，自动 fallback WebGL2）(evidence: [T03-S002])"
  "**处理异步初始化（关键）**：\`await renderer.init()\` 后才能 setSize/渲染 (evidence: [T03-S002])"
  "**改写后期**：EffectComposer/旧后期 → TSL-native 或逐 pass 验证兼容 (evidence: [T03-S002])"
  "**GLSL → TSL**：自定义 shader 改写 Three Shading Language（一次编译跨 WGSL/GLSL）(evidence: [T03-S002, T02-S031])"
  "**fallback 检测 + 跨浏览器测**：查 \`navigator.gpu\` 优雅回退；Chrome/Firefox/Safari（macOS+iOS 分测），Safari 有 timestamp query/纹理格式怪癖 (evidence: [T03-S002])"
)
declare -a FAILURE_MODES=(
  "忘 \`await renderer.init()\` → 白屏无报错：init 必 await (evidence: [T03-S002])"
  "混用 \`three\` 与 \`three/webgpu\` import → 出错：统一用 \`three/webgpu\` (evidence: [T03-S002])"
  "自定义 ShaderMaterial/EffectComposer 直接搬 → 失效：改写 TSL/新后期栈 (evidence: [T03-S002])"
  "不测 Safari → 上线 Safari 崩：Safari 怪癖最多，早测 (evidence: [T03-S002])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "webgl-webgpu-tsl-walkthrough"
fi
